        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "년월 ["+ str +"]",
        textAlign : "left",    
